const raw = $input.first().json;
let task = '';
try {
  const parsed = JSON.parse(raw.query || '{}');
  task = parsed.task || parsed.description || parsed.prompt || raw.query || '';
} catch (error) {
  task = raw.task || raw.query || JSON.stringify(raw);
}
const prompt = `You are an n8n workflow engineer. Build a complete working workflow for this task:

${task}

Reference file: /home/node/.n8n/openclaw-reference/workflow-builder.md

Rules:
- Use the local n8n public API with curl only when required.
- For local self-inspection, prefer {{ $env.N8N_INTERNAL_URL }}.
- n8n expressions must start with =, for example ={{ $json.field }}
- Return concise implementation notes after you create or update the workflow.`;
return [{ json: { prompt, task } }];

const result = $input.first().json;
const output = result.stdout || result.data || result.output || result.result || JSON.stringify(result);
return [{ json: {
  response: output || 'Claude Code completed but returned no text output.',
  exitCode: result.exitCode ?? null,
  stderr: result.stderr || null
} }];
